mapper.select:
SELECT ID, COMPANY_ID, COMPANY_NAME, DEPT_ID, DEPT_NAME, WORK_DATE, CLASS_CODE, CLASS_NAME, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME FROM T_PRD_ATTENDANCE
DEPT_ID IN ( SELECT ID FROM ( SELECT ID,DEPT_NAME,DEPT_LEVEL FROM SYS_DEPT START WITH ID =(SELECT ID FROM SYS_DEPT WHERE ID = ( SELECT DEPT_ID FROM sys_user WHERE ID = #{loginUserId,jdbcTypeName=BIGINT} )) CONNECT BY PRIOR ID=PARENT_ID )WHERE DEPT_LEVEL IN (3,4))
and ID = #{id}
and COMPANY_ID = #{companyId}
and DEPT_ID = #{deptId}
and WORK_DATE =#{workDate}
order by WORK_DATE desc

mapper.insert:
INSERT INTO T_PRD_ATTENDANCE_USER( ID, ATTENDANCE_ID, USER_ID, USER_NAME, COEFFICIENT, ISWORK, CREATE_BY, CREATE_BY_NAME, CREATE_TIME) (
SELECT #{item.id, jdbcType=BIGINT}, #{item.attendanceId, jdbcType=BIGINT}, #{item.userId, jdbcType=VARCHAR}, #{item.userName, jdbcType=VARCHAR}, #{item.coefficient, jdbcType=BIGINT}, #{item.iswork, jdbcType=VARCHAR}, #{item.createBy, jdbcType=BIGINT}, #{item.createByName, jdbcType=VARCHAR}, #{item.createTime} FROM DUAL
)

update.foreach:
update T_PRD_ATTENDANCE_USER


        COEFFICIENT=#{item.coefficient},


        ISWORK=#{item.iswork},

    UPDATE_BY = #{item.updateBy},
    UPDATE_BY_NAME = #{item.updateByName},
    UPDATE_TIME = #{item.updateTime}


    ID =#{item.id}
    AND ATTENDANCE_ID = #{item.attendanceId}
    and USER_ID = #{item.userId}
    and USER_NAME = #{item.userName}

mapper.select:
SELECT * FROM
    T_PRD_ATTENDANCE
WHERE COMPANY_NAME like concat(concat('%', #{companyName}), '%')
        and WORK_DATE =#{workDate}
        and CLASS_NAME = #{className}

mapper.insert:
INSERT INTO T_PRD_ATTENDANCE_USER( ID, ATTENDANCE_ID, USER_ID, USER_NAME, COEFFICIENT, ISWORK, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME) (
SELECT #{item.id, jdbcType=BIGINT}, #{item.attendanceId, jdbcType=BIGINT}, #{item.userId, jdbcType=VARCHAR}, #{item.userName, jdbcType=VARCHAR}, #{item.coefficient, jdbcType=BIGINT}, #{item.iswork, jdbcType=VARCHAR}, #{item.createBy, jdbcType=BIGINT}, #{item.createByName, jdbcType=VARCHAR}, #{item.createTime}, #{item.updateBy}, #{item.updateByName}, #{item.updateTime} FROM DUAL
)

mapper.select:
SELECT u.ID, u.USER_ACCOUNT, u.USER_NAME, u.DEPT_ID, u.IS_SUPERADMIN, DECODE(u.IS_SUPERADMIN, '1', '是', '否') IS_SUPERADMIN_LABEL, u.MOBILE, u.EMAIL, u.STATUS, u.REMARK, DECODE(u.STATUS, '1', '在用', '停用') STATUS_LABEL, u.PSD_UPD_DATE, u.SORT_NUM, u.UPDATE_TIME, u.CREATE_TIME, u.POST_CODE, u.POST_NAME, u.UNIT_TYPE_CODE, u.UNIT_TYPE_NAME, d.DEPT_NAME FROM SYS_USER u JOIN SYS_DEPT d ON u.DEPT_ID = d.ID
AND (u.USER_ACCOUNT LIKE #{userAccount,jdbcType=VARCHAR})
AND (u.USER_NAME LIKE #{userName,jdbcType=VARCHAR})
AND (instr(d.PARENT_IDS, #{deptId,jdbcType=BIGINT}) > 0 OR d.ID = #{deptId,jdbcType=BIGINT})
AND u.STATUS = #{status}
AND u.IS_SUPERADMIN = #{isSuperadmin}
${params.dataScope}
ORDER BY u.SORT_NUM

mapper.delete:
DELETE FROM
    T_PRD_ATTENDANCE
WHERE COMPANY_NAME like concat(concat('%', #{companyName}), '%')
        and DEPT_ID = #{deptId}
        and WORK_DATE =#{workDate}
        and CLASS_NAME = #{className}
